                // Reading from mere reservations of mutable-borrows is OK.
                if !is_active(this.dominators(), borrow, location) {
                    assert!(borrow.kind.allows_two_phase_borrow());
                    return ControlFlow::Continue(());
                }

                error_reported = true;
                match kind {
                    ReadKind::Copy => {
                        let err = this
