                    place_span,
                    sd,
                    rw,
                    (borrow_index, borrow),
                );
                ControlFlow::Continue(())
            }

            (Read(_), BorrowKind::Shared | BorrowKind::Fake(_))
            | (
                Read(ReadKind::Borrow(BorrowKind::Fake(FakeBorrowKind::Shallow))),
                BorrowKind::Mut { .. },
